{
  "children": [
    {
      "name": "IngestData",
      "purpose": "Read and store raw input data into raw_data store",
      "behavior": "Parse input JSON, extract source, read data from source, store in raw_data, log ingestion",
      "boundary": {
        "in_scope": [
          "reading input source",
          "storing raw data",
          "logging ingestion"
        ],
        "out_of_scope": [
          "transformation",
          "validation",
          "export"
        ]
      },
      "semantic_inputs": [
        {
          "name": "input",
          "description": "JSON with action and source",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "ingestion_result",
          "description": "JSON with success status and records count",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "input contains valid source"
      ],
      "postconditions": [
        "raw_data store populated"
      ],
      "guarantees": [
        "raw_data is stored for further processing"
      ],
      "composition_role": "transform",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [
        {
          "name": "input",
          "type": "dict",
          "description": "JSON with action and source",
          "source": "parent input"
        }
      ],
      "internal_leaf_accesses": [
        {
          "resource": "raw_data",
          "op": "write",
          "reason": "store ingested raw data for downstream processing"
        }
      ],
      "outputs": [
        {
          "name": "ingestion_result",
          "type": "dict",
          "description": "JSON with success status and records count",
          "consumer": "parent"
        }
      ],
      "signature": "def IngestData(input: dict) -> dict"
    },
    {
      "name": "TransformData",
      "purpose": "Apply transformation rules to raw data and store in processed_data",
      "behavior": "Read raw_data, apply transformations (e.g., cleaning, mapping), write to processed_data, log transformation",
      "boundary": {
        "in_scope": [
          "reading raw_data",
          "applying transformations",
          "writing processed_data",
          "logging"
        ],
        "out_of_scope": [
          "ingestion",
          "validation",
          "export"
        ]
      },
      "semantic_inputs": [
        {
          "name": "raw_data",
          "description": "Data from raw_data store",
          "source": "internal leaf access"
        }
      ],
      "semantic_outputs": [
        {
          "name": "transformation_result",
          "description": "JSON with success status and records transformed",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "raw_data is available"
      ],
      "postconditions": [
        "processed_data store populated"
      ],
      "guarantees": [
        "transformed data is stored"
      ],
      "composition_role": "transform",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [],
      "internal_leaf_accesses": [
        {
          "resource": "raw_data",
          "op": "read",
          "reason": "read raw data for transformation"
        },
        {
          "resource": "processed_data",
          "op": "write",
          "reason": "store transformed data for validation"
        }
      ],
      "outputs": [
        {
          "name": "transformation_result",
          "type": "dict",
          "description": "JSON with success status and records transformed",
          "consumer": "parent"
        }
      ],
      "signature": "def TransformData() -> dict"
    },
    {
      "name": "ValidateQuality",
      "purpose": "Check processed data for quality and filter valid records",
      "behavior": "Read processed_data, apply validation rules (e.g., schema, range), mark invalid records, log validation results",
      "boundary": {
        "in_scope": [
          "reading processed_data",
          "validating records",
          "filtering invalid",
          "logging"
        ],
        "out_of_scope": [
          "ingestion",
          "transformation",
          "export"
        ]
      },
      "semantic_inputs": [
        {
          "name": "processed_data",
          "description": "Data from processed_data store",
          "source": "internal leaf access"
        }
      ],
      "semantic_outputs": [
        {
          "name": "validation_result",
          "description": "JSON with valid records count and errors list",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "processed_data is available"
      ],
      "postconditions": [
        "valid records identified"
      ],
      "guarantees": [
        "invalid records are excluded from export"
      ],
      "composition_role": "validate",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [],
      "internal_leaf_accesses": [
        {
          "resource": "processed_data",
          "op": "read",
          "reason": "read processed data for validation"
        }
      ],
      "outputs": [
        {
          "name": "validation_result",
          "type": "dict",
          "description": "JSON with valid records count and errors list",
          "consumer": "parent"
        }
      ],
      "signature": "def ValidateQuality() -> dict"
    },
    {
      "name": "ExportResults",
      "purpose": "Export only valid records to output",
      "behavior": "Read valid records from processed_data (based on validation), format output JSON with success, records_processed, errors, data, log export",
      "boundary": {
        "in_scope": [
          "reading valid records",
          "formatting output",
          "logging export"
        ],
        "out_of_scope": [
          "ingestion",
          "transformation",
          "validation"
        ]
      },
      "semantic_inputs": [
        {
          "name": "valid_records",
          "description": "Indication of which records are valid from validation",
          "source": "previous child output"
        }
      ],
      "semantic_outputs": [
        {
          "name": "output",
          "description": "Final JSON with success, records_processed, errors, data",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "validation completed"
      ],
      "postconditions": [
        "output is produced"
      ],
      "guarantees": [
        "only valid records are exported"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [
        {
          "name": "validation_result",
          "type": "dict",
          "description": "Validation result containing valid records info",
          "source": "ValidateQuality output"
        }
      ],
      "internal_leaf_accesses": [
        {
          "resource": "processed_data",
          "op": "read",
          "reason": "read processed data to extract valid records"
        }
      ],
      "outputs": [
        {
          "name": "output",
          "type": "dict",
          "description": "Final JSON with success, records_processed, errors, data",
          "consumer": "parent"
        }
      ],
      "signature": "def ExportResults(validation_result: dict) -> dict"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {
      "input": "IngestData"
    },
    "parent_outputs_produced_by": {
      "output": "ExportResults"
    }
  },
  "dataflow_edges": [
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "IngestData",
      "to_input": "input",
      "note": "parent passes input to IngestData"
    },
    {
      "from_node": "IngestData",
      "from_output": "ingestion_result",
      "to_node": "parent",
      "to_input": "ingestion_result",
      "note": "IngestData returns status to parent"
    },
    {
      "from_node": "parent",
      "from_output": "trigger",
      "to_node": "TransformData",
      "to_input": "trigger",
      "note": "parent triggers TransformData after ingestion"
    },
    {
      "from_node": "TransformData",
      "from_output": "transformation_result",
      "to_node": "parent",
      "to_input": "transformation_result",
      "note": "TransformData returns status to parent"
    },
    {
      "from_node": "parent",
      "from_output": "trigger",
      "to_node": "ValidateQuality",
      "to_input": "trigger",
      "note": "parent triggers ValidateQuality after transform"
    },
    {
      "from_node": "ValidateQuality",
      "from_output": "validation_result",
      "to_node": "parent",
      "to_input": "validation_result",
      "note": "ValidateQuality returns validation result to parent"
    },
    {
      "from_node": "parent",
      "from_output": "validation_result",
      "to_node": "ExportResults",
      "to_input": "validation_result",
      "note": "parent passes validation result to ExportResults"
    },
    {
      "from_node": "ExportResults",
      "from_output": "output",
      "to_node": "parent",
      "to_input": "output",
      "note": "ExportResults returns final output to parent"
    }
  ],
  "interface_audit": {
    "identity_preservation_detail": "All four child names (IngestData, TransformData, ValidateQuality, ExportResults) are preserved exactly as in Stage 1. No children were added, deleted, renamed, or reordered.",
    "semantic_preservation_detail": "All Stage 1 fields (purpose, behavior, boundary, preconditions, postconditions, guarantees, composition_role) are copied verbatim without any changes.",
    "call_signature_detail": "Only call_inputs appear in the Python signature. IngestData receives 'input' from parent. TransformData and ValidateQuality have no call_inputs (they access data stores internally). ExportResults receives 'validation_result' from parent. Internal leaf accesses (raw_data, processed_data) are excluded from signatures.",
    "internal_leaf_separation_detail": "Data stores (raw_data, processed_data) are listed under internal_leaf_accesses, not call_inputs, because they are accessed internally by the child's implementation and not passed by the parent. This keeps the interface clean and the signature focused on parent-child communication.",
    "dataflow_schema_detail": "All dataflow edges use only 'parent' or exact child names as from_node/to_node. No resource/store names (raw_data, processed_data) appear as endpoints. Edges correctly connect parent to children and children back to parent.",
    "final_status": "ok"
  }
}
